class TestZipDictsHappyPath:
    """Tests for standard, expected usage."""

    def test_two_dicts_partial_overlap(self):
        assert zip_dicts({'a': 1, 'b': 2}, {'b': 3, 'c': 4}) == {
            'a': [1, None],
            'b': [2, 3],
            'c': [None, 4]
        }

    def test_three_dicts_full_overlap(self):
        assert zip_dicts({'x': 1}, {'x': 2}, {'x': 3}) == {'x': [1, 2, 3]}

    def test_no_overlap_across_dicts(self):
        assert zip_dicts({'a': 1}, {'b': 2}, {'c': 3}) == {
            'a': [1, None, None],
            'b': [None, 2, None],
            'c': [None, None, 3]
        }

    def test_preserves_input_order_in_value_lists(self):
        d1, d2, d3 = {'k': 1}, {'k': 2}, {'k': 3}
        assert zip_dicts(d1, d2, d3) == {'k': [1, 2, 3]}
        assert zip_dicts(d3, d1, d2) == {'k': [3, 1, 2]}

    @pytest.mark.parametrize("d1,d2,expected", [
        ({'a': [1, 2]}, {'a': 'str'}, {'a': [[1, 2], 'str']}),
        ({'a': {'nested': True}}, {'a': 42}, {'a': [{'nested': True}, 42]}),
        ({'a': 0}, {'a': False}, {'a': [0, False]}),
        ({'a': ""}, {'a': []}, {'a': ["", []]}),
    ])
    def test_various_value_types(self, d1, d2, expected):
        assert zip_dicts(d1, d2) == expected


class TestZipDictsEdgeCases:
    """Tests for boundary conditions and unusual but valid inputs."""

    def test_no_arguments(self):
        assert zip_dicts() == {}

    def test_single_empty_dict(self):
        assert zip_dicts({}) == {}

    def test_multiple_empty_dicts(self):
        assert zip_dicts({}, {}, {}) == {}

    def test_single_dict_with_values(self):
        assert zip_dicts({'a': 1, 'b': 2}) == {'a': [1], 'b': [2]}

    def test_explicit_none_vs_missing_key(self):
        # Note: d.get(k) returns None for missing keys.
        # The function does not distinguish between explicit None and missing keys.
        d1 = {'a': None}
        d2 = {}
        assert zip_dicts(d1, d2) == {'a': [None, None]}

    def test_mixed_hashable_key_types(self):
        d1 = {1: 'int', (2, 3): 'tuple'}
        d2 = {'str': 'val', 1: 'overlap'}
        result = zip_dicts(d1, d2)
        assert result == {
            1: ['int', 'overlap'],
            (2, 3): ['tuple', None],
            'str': [None, 'val']
        }

    def test_dict_subclasses(self):
        d1 = OrderedDict([('a', 1)])
        d2 = defaultdict(int, {'b': 2})
        assert zip_dicts(d1, d2) == {'a': [1, None], 'b': [None, 2]}

    def test_many_dicts_performance_boundary(self):
        dicts = [{f'k{i}': i} for i in range(50)]
        result = zip_dicts(*dicts)
        assert len(result) == 50
        for i in range(50):
            expected = [None] * 50
            expected[i] = i
            assert result[f'k{i}'] == expected


